// Extrae información relevante del payload de GitHub
const payload = $input.first().json;
const body = payload.body ?? payload;

const branch = body.ref?.replace('refs/heads/', '') ?? 'main';
const repoFullName = body.repository?.full_name ?? '';
const commitSha = body.after ?? body.head_commit?.id ?? '';
const pusher = body.pusher?.name ?? 'unknown';

// Verificar si el push incluye cambios en archivos YAML de API
const changedFiles = body.commits?.flatMap(c => [
  ...(c.added ?? []),
  ...(c.modified ?? [])
]) ?? [];

const hasOasChanges = changedFiles.some(f => 
  f.endsWith('.yaml') || f.endsWith('.yml')
);

return [{
  json: {
    branch,
    repoFullName,
    commitSha,
    pusher,
    hasOasChanges,
    changedFiles,
    rawUrl: `https://raw.githubusercontent.com/${repoFullName}/${branch}/openapi.yaml`,
    timestamp: new Date().toISOString()
  }
}];

// Guardar el YAML en el filesystem donde corre N8N
// para que el script de pipeline pueda leerlo
const fs = require('fs');
const path = require('path');

const yamlContent = $input.first().json.data ?? $input.first().json;
const workDir = process.env.PIPELINE_WORK_DIR ?? '/tmp/oas-pipeline';

fs.mkdirSync(workDir, { recursive: true });
fs.writeFileSync(path.join(workDir, 'openapi.yaml'), yamlContent, 'utf8');

return [{
  json: {
    ...$('Extraer info del push').first().json,
    workDir,
    yamlPath: path.join(workDir, 'openapi.yaml')
  }
}];

// Parsear el resultado del pipeline
const output = $input.first().json.stdout ?? '';
const exitCode = $input.first().json.exitCode ?? 0;

let result;
try {
  // El script emite el JSON como última línea de stdout
  const lines = output.trim().split('\n');
  const jsonLine = lines.reverse().find(l => l.trim().startsWith('{'));
  result = JSON.parse(jsonLine ?? '{}');
} catch {
  result = { status: exitCode === 0 ? 'PASSED' : 'FAILED', raw: output };
}

return [{
  json: {
    ...result,
    exitCode,
    branch: $('Extraer info del push').first().json.branch,
    commitSha: $('Extraer info del push').first().json.commitSha,
    pusher: $('Extraer info del push').first().json.pusher,
    passed: result.status === 'PASSED'
  }
}];

